  '[{"title": "Intelligent document processing for Sevenoaks professionals", "description": "AI systems that read, classify, and extract information from documents automatically. Contracts, invoices, client correspondence, and compliance documents are processed intelligently, extracting key data points and routing information to the right team member or system. Hours of manual review reduced to minutes."}, {"title": "AI-powered client communication for premium service delivery", "description": "Draft client emails, progress updates, and routine correspondence using AI trained on your communication style and service standards. Every output matches the professional tone Sevenoaks clients expect. Your team reviews and personalises rather than writing from scratch, maintaining quality while dramatically reducing time."}, {"title": "Intelligent workflow routing for Sevenoaks business operations", "description": "AI that classifies incoming enquiries, routes tasks to the appropriate team member based on expertise and capacity, and prioritises work based on deadline and value. Your Sevenoaks business operates with the coordination of a firm three times your size without the overhead."}]',
